Here is a Python implementation of the binary search algorithm. It efficiently finds the index of a target value within a sorted array, returning -1 if the target is not found.

def binary_search(arr, target):
    if not isinstance(arr, list):
        raise ValueError('Input must be a list')

    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# Example usage:
# result = binary_search([1, 2, 3, 4, 5], 3) # Returns 2

